///
/// * `sk` - The secret key
/// * `hash_point` - Pre-computed hash point (512 coefficients in [0, Q))
/// * `seed` - 56-byte seed for the sampling PRNG
///
/// # Returns
///
/// `(s0, s1)` where s0 + s1*h = hash_point (mod q) and ||(s0, s1)|| is small.
/// Coefficients are signed integers (centered around 0).
pub fn sign_prehashed(
    sk: &SecretKey,
    hash_point: &[i16; N],
    seed: &[u8; SEED_LEN],
) -> (Vec<i32>, Vec<i32>) {
    let hashed_i32: Vec<i32> = hash_point.iter().map(|&x| x as i32).collect();
    let mut current_seed = *seed;

    loop {
        let mut rng = ChaCha20::new(&current_seed);
        let mut random_bytes = |n: usize| rng.random_bytes(n);

        let (s0, s1) = Self::sample_preimage(sk, &hashed_i32, &mut random_bytes);

        let s0_slice: &[i32] = &s0;
        let s1_slice: &[i32] = &s1;
        let norm = sqnorm(&[s0_slice, s1_slice]);

        if norm <= SIG_BOUND {
            return (s0, s1);
        }

        // Advance seed
        current_seed[SALT_LEN..].copy_from_slice(&rng.random_bytes(SEED_LEN - SALT_LEN)[..]);
    }
}

/// Sample a short preimage s such that s0 + s1*h = point.
fn sample_preimage<F: FnMut(usize) -> Vec<u8>>(
    sk: &SecretKey,
    point: &[i32],
    random_bytes: &mut F,
) -> (Vec<i32>, Vec<i32>) {
    let [[a, b], [c, d]] = &sk.b0_fft;

    // Compute t_fft = (point, 0) * B0^(-1)
    // Because the inverse of B0 has a specific form, we can optimize
    let point_fft = fft(&point.iter().map(|&x| x as f64).collect::<Vec<_>>());
    let q_f64 = Q as f64;

    let t0_fft: Vec<Complex> = point_fft
        .iter()
        .zip(d.iter())
        .map(|(&p, &d_i)| {
            Complex::new(
                p.re * d_i.re / q_f64 - p.im * d_i.im / q_f64,
                p.re * d_i.im / q_f64 + p.im * d_i.re / q_f64,
            )
        })
        .collect();

